import { ComponentPropsWithoutRef } from 'react';
import {
  Copy01,
  DownloadCloud02,
  Edit04,
  RefreshCcw02,
  Stars02,
} from '@untitledui/icons';
import { Button } from '@/components/atoms/Button';
import { WithDataId } from '@/types/withDataId';

export type MessageActionButtonProps = ComponentPropsWithoutRef<typeof Button> &
  WithDataId & {
    icon: 'ai' | 'copy' | 'reply' | 'edit' | 'download';
    title: string;
  };

export function MessageActionButton({
  icon,
  ...buttonProps
}: MessageActionButtonProps) {
  let Icon = null;
  switch (icon) {
    case 'ai':
      Icon = Stars02;
      break;
    case 'copy':
      Icon = Copy01;
      break;
    case 'reply':
      Icon = RefreshCcw02;
      break;
    case 'edit':
      Icon = Edit04;
      break;
    case 'download':
      Icon = DownloadCloud02;
      break;
    default:
      Icon = null;
  }

  if (!Icon) {
    return null;
  }

  return (
    <Button
      aria-label={buttonProps.title}
      className="cursor-pointer rounded p-0.5 text-fg-quaternary outline-focus-ring transition duration-100 ease-linear hover:text-fg-quaternary_hover focus-visible:outline-2 focus-visible:outline-offset-2"
      {...buttonProps}
    >
      <Icon className="size-4" />
    </Button>
  );
}
